/*
 * Parallel Trapezoidal Rule using MPI
 * Integrates f(x) = x^2 from a to b using multiple MPI processes
 * 
 * Compile: mpicc -o trapezoidal_mpi trapezoidal_mpi.c
 * Run: mpirun -np 4 ./trapezoidal_mpi
 */

#include <mpi.h>
#include <stdio.h>
#include <stdlib.h>

/* Function to integrate: f(x) = x^2 */
double f(double x) {
 return x * x;
}

/* Trapezoidal rule for local interval */
double trapezoidal_rule(double local_a, double local_b, int local_n) {
 double h = (local_b - local_a) / local_n;
 double integral = (f(local_a) + f(local_b)) / 2.0;

 for (int i = 1; i < local_n; i++) {
 double x = local_a + i * h;
 integral += f(x);
 }

 integral *= h;
 return integral;
}

int main(int argc, char** argv) {
 int my_rank, num_procs;
 int n = 10000; /* Total number of subintervals */
 double a = 0.0; /* Lower bound */
 double b = 1.0; /* Upper bound */
 double h; /* Step size */

 double local_a, local_b;
 int local_n;
 double local_integral, total_integral;

 /* Initialize MPI environment */
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &my_rank);
 MPI_Comm_size(MPI_COMM_WORLD, &num_procs);

 /* Process 0 reads input parameters */
 if (my_rank == 0) {
 printf("========================================\n");
 printf("Parallel Trapezoidal Rule with MPI\n");
 printf("========================================\n");
 printf("Integrating f(x) = x^2 from %.1f to %.1f\n", a, b);
 printf("Total subintervals: %d\n", n);
 printf("Number of processes: %d\n\n", num_procs);
 }

 /* Broadcast input parameters to all processes */
 MPI_Bcast(&a, 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);
 MPI_Bcast(&b, 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);
 MPI_Bcast(&n, 1, MPI_INT, 0, MPI_COMM_WORLD);

 /* Calculate step size and local bounds */
 h = (b - a) / n;

 /* Domain decomposition: distribute subintervals among processes */
 local_n = n / num_procs;
 int remainder = n % num_procs;

 /* Distribute extra subintervals to first 'remainder' processes */
 if (my_rank < remainder) {
 local_n++;
 }

 /* Calculate local integration bounds */
 local_a = a + my_rank * (b - a) / num_procs;
 local_b = a + (my_rank + 1) * (b - a) / num_procs;

 /* Each process computes its local integral */
 local_integral = trapezoidal_rule(local_a, local_b, local_n);

 /* Print local results */
 printf("Process %d: local_a=%.6f, local_b=%.6f, "
 "local_n=%d, local_integral=%.10f\n",
 my_rank, local_a, local_b, local_n, local_integral);

 /* Synchronize before reduction */
 MPI_Barrier(MPI_COMM_WORLD);

 /* Reduce all local integrals to get total result (sum on root) */
 MPI_Reduce(&local_integral, &total_integral, 1, MPI_DOUBLE,
 MPI_SUM, 0, MPI_COMM_WORLD);

 /* Process 0 prints final result */
 if (my_rank == 0) {
 double exact = (b*b*b - a*a*a) / 3.0; /* Exact integral of x^2 */
 double error = fabs(total_integral - exact);

 printf("\n========================================\n");
 printf("RESULTS\n");
 printf("========================================\n");
 printf("Approximate integral: %.15f\n", total_integral);
 printf("Exact integral: %.15f\n", exact);
 printf("Absolute error: %.15e\n", error);
 printf("========================================\n");
 }

 /* Finalize MPI environment */
 MPI_Finalize();

 return 0;
}
